class Solution:
    def minMirrorPairDistance(self, nums):
        n = len(nums)
        best = -1
        for i in range(n):
            ri = int(str(nums[i])[::-1])
            for j in range(i + 1, n):
                if ri == nums[j]:
                    d = j - i
                    if best == -1 or d < best:
                        best = d
        return best

