class Solution:
    def minMirrorPairDistance(self, nums: List[int]) -> int:
        pending = {}
        best = -1
        for j, x in enumerate(nums):
            if x in pending:
                d = j - pending[x]
                if best == -1 or d < best:
                    best = d
            r = int(str(x)[::-1])
            pending[r] = j
        return best

