var minMirrorPairDistance = function(nums) {
    const pending = new Map();
    let best = -1;
    for (let j = 0; j < nums.length; j++) {
        const x = nums[j];
        if (pending.has(x)) {
            const d = j - pending.get(x);
            if (best === -1 || d < best) best = d;
        }
        const r = parseInt(x.toString().split('').reverse().join(''), 10);
        pending.set(r, j);
    }
    return best;
};
